async function loadLeaderboard(){$("lb-loader").classList.add("show"),$("lb-tbl").style.display="none";try{renderLeaderboard(await apiFetch("GET","/leaderboard"))}catch(e){$("lb-tbody").innerHTML='<tr><td colspan="5" style="padding:20px;color:var(--rd);text-align:center">'+escHtml(e.message)+"</td></tr>",$("lb-tbl").style.display=""}finally{$("lb-loader").classList.remove("show")}}function renderLeaderboard(e){if(!e||!e.length)return $("lb-tbody").innerHTML='<tr><td colspan="5"><div class="empty"><div class="empty-title">ŽEBŘÍČEK JE PRÁZDNÝ</div><div class="empty-sub">BUĎ PRVNÍ!</div></div></td></tr>',void($("lb-tbl").style.display="");const l=e.slice().sort((e,l)=>(l.elo_rating||1e3)-(e.elo_rating||1e3)),t=currentUser?currentUser.username:null;$("lb-tbody").innerHTML=l.map((e,l)=>{const s=l+1,a=1===s?"p1":2===s?"p2":3===s?"p3":"",d=e.username===t;return'<tr class="'+(d?"me":"")+'"><td><div class="lb-pos '+a+'">'+s+'</div></td><td><div class="lb-club-name">'+escHtml(e.club_name||e.username)+(d?" &laquo;":"")+'</div><div class="lb-club-handle">@'+escHtml(e.username)+'</div></td><td><div class="lb-elo">'+(e.elo_rating||1e3)+'</div></td><td class="lb-r hide-m" style="font-family:\'Bebas Neue\',sans-serif;font-size:20px;color:var(--or)">'+(e.level||1)+'</td><td class="lb-r hide-m" style="color:var(--yw);font-weight:700">'+(e.money||0)+"</td></tr>"}).join(""),$("lb-tbl").style.display=""}